1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const BLOCK_OF_3_BASE_PREMIUM = 60;
5	
6	const BASE_PREMIUM: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
16	
17	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
18	type Step = { op: "quote"; items: Item[] };
19	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
20	type QuoteResult = { premium: number };
21	
22	const withFirstInsurance = (base: number): number =>
23	  base + base * FIRST_INSURANCE_SURCHARGE_RATE;
24	
25	const itemPremium = (item: Item): number => {
26	  const base = BASE_PREMIUM[item.type];
27	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
28	  const highEnchSurcharge = (item.enchantment ?? 0) >= 5 ? base * 0.3 : 0;
29	  return withFirstInsurance(base) + curseSurcharge + highEnchSurcharge;
30	};
31	
32	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
33	
34	const componentGroupPremium = (type: string, count: number): number =>
35	  count === 3
36	    ? withFirstInsurance(BLOCK_OF_3_BASE_PREMIUM)
37	    : count * itemPremium({ type });
38	
39	const countByType = (items: Item[]): Map<string, number> => {
40	  const counts = new Map<string, number>();
41	  for (const item of items) {
42	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
43	  }
44	  return counts;
45	};
46	
47	const sumComponentPremiums = (components: Item[]): number =>
48	  Array.from(countByType(components)).reduce(
49	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
50	    0,
51	  );
52	
53	const sumMainItemPremiums = (mainItems: Item[]): number =>
54	  mainItems.reduce((sum, item) => sum + itemPremium(item), 0);
55	
56	const sumItemPremiums = (items: Item[]): number => {
57	  const components = items.filter(isComponent);
58	  const mainItems = items.filter((item) => !isComponent(item));
59	  return sumMainItemPremiums(mainItems) + sumComponentPremiums(components);
60	};
61	
62	const quoteStep = (step: Step): QuoteResult => ({
63	  premium: Math.ceil(sumItemPremiums(step.items) + PROCESSING_FEE),
64	});
65	
66	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
67	  results: scenario.steps.map(quoteStep),
68	});
